module top_module(
  input clk,
  input rst_n,
  input IRWrite,
  input [31:0] Instr_i,

  output [31:0] Instr_o
  );reg [31:0] IR;
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst_n or posedge dbg_halt)
  begin
    if (rst_n)
      IR <= 32'h0;
    else
      begin
        if (IRWrite)
          IR <= Instr_i;
      end
  end
  assign Instr_o = IR;
endmodule
